input.content:
$env:PINCHTAB_URL = "http://localhost:9868"
$tabId = "tab_c3763dd8"

# Extract story title, points, and comment count
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    // Get title
    var titleEl = document.querySelector('.titleline a');
    var title = titleEl ? titleEl.textContent.trim() : 'N/A';

    // Get points
    var scoreEl = document.querySelector('.score');
    var points = scoreEl ? scoreEl.textContent.trim() : 'N/A';

    // Get comment count from subtext
    var subtextLinks = document.querySelectorAll('.subtext a');
    var commentCount = 'N/A';
    for (var i = 0; i < subtextLinks.length; i++) {
        if (subtextLinks[i].href.includes('item')) {
            commentCount = subtextLinks[i].textContent.trim();
        }
    }

    return JSON.stringify({title: title, points: points, commentCount: commentCount});
})()
"@
} | ConvertTo-Json)

Write-Host "Story Info: $($response.result)"

$env:PINCHTAB_URL = "http://localhost:9868"
$tabId = "tab_c3763dd8"

# Find the top-level comment with most direct replies
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    // Get all comment rows
    var rows = document.querySelectorAll('.comtr');

    // HN uses indentation levels (indent attribute on .ind img) to determine depth
    // Top-level comments have indent = 0
    // Replies to them have indent = 40, etc. (40px per level)

    var results = [];

    for (var i = 0; i < rows.length; i++) {
        var row = rows[i];
        var indEl = row.querySelector('.ind img');
        if (!indEl) continue;
        var indWidth = parseInt(indEl.getAttribute('width') || '0');

        // Top-level comments have indent width = 0
        if (indWidth === 0) {
            var authorEl = row.querySelector('.hnuser');
            var author = authorEl ? authorEl.textContent.trim() : 'unknown';
            var commentId = row.getAttribute('id');

            // Count direct replies (next rows with indent = 40 before another indent 0)
            var directReplies = 0;
            for (var j = i + 1; j < rows.length; j++) {
                var nextIndEl = rows[j].querySelector('.ind img');
                if (!nextIndEl) continue;
                var nextIndWidth = parseInt(nextIndEl.getAttribute('width') || '0');
                if (nextIndWidth === 0) break; // back to top level
                if (nextIndWidth === 40) directReplies++; // direct reply (1 level deep)
            }

            results.push({author: author, directReplies: directReplies, id: commentId});
        }
    }

    // Sort by direct replies descending
    results.sort(function(a, b) { return b.directReplies - a.directReplies; });

    return JSON.stringify(results.slice(0, 10));
})()
"@
} | ConvertTo-Json)

Write-Host "Top-level comments by direct replies:"
Write-Host $response.result

$env:PINCHTAB_URL = "http://localhost:9868"
$tabId = "tab_c3763dd8"

# Get full comment count from the page header
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    // Count all comment rows actually displayed
    var rows = document.querySelectorAll('.comtr');
    var totalRows = rows.length;

    // Get the points from the score element
    var scoreEl = document.querySelector('.score');
    var points = scoreEl ? scoreEl.textContent.trim() : 'N/A';

    // Get the comment count link text from subtext  
    var subtextLinks = document.querySelectorAll('.subtext a');
    var commentLinkText = '';
    for (var i = 0; i < subtextLinks.length; i++) {
        var href = subtextLinks[i].getAttribute('href');
        if (href && href.startsWith('item')) {
            commentLinkText = subtextLinks[i].textContent.trim();
        }
    }

    return JSON.stringify({
        points: points,
        commentLinkText: commentLinkText,
        totalCommentRowsDisplayed: totalRows
    });
})()
"@
} | ConvertTo-Json)

Write-Host "Comment page info: $($response.result)"

