input.content:
$env:PINCHTAB_URL = "http://localhost:9868"
$tabId = "tab_c3763dd8"

# Get detailed structure of top-level comments and their replies
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    var rows = document.querySelectorAll('.comtr');
    var allComments = [];

    for (var i = 0; i < rows.length; i++) {
        var row = rows[i];
        var indEl = row.querySelector('.ind img');
        if (!indEl) continue;
        var indWidth = parseInt(indEl.getAttribute('width') || '0');
        var depth = indWidth / 40; // 40px per level

        var authorEl = row.querySelector('.hnuser');
        var author = authorEl ? authorEl.textContent.trim() : 'unknown';

        allComments.push({depth: depth, author: author});
    }

    // Now build tree: for each top-level (depth=0), count direct replies (depth=1 before next depth=0)
    var tlComments = [];
    for (var i = 0; i < allComments.length; i++) {
        if (allComments[i].depth === 0) {
            var directReplies = 0;
            for (var j = i + 1; j < allComments.length; j++) {
                if (allComments[j].depth === 0) break;
                if (allComments[j].depth === 1) directReplies++;
            }
            tlComments.push({author: allComments[i].author, directReplies: directReplies, position: i});
        }
    }

    return JSON.stringify({allComments: allComments, topLevel: tlComments});
})()
"@
} | ConvertTo-Json)

# Parse and display
$data = $response.result | ConvertFrom-Json
Write-Host "=== All comments with depth ==="
$data.allComments | ForEach-Object { Write-Host "Depth: $($_.depth), Author: $($_.author)" }
Write-Host ""
Write-Host "=== Top-level comments with direct replies ==="
$data.topLevel | ForEach-Object { Write-Host "Author: $($_.author), DirectReplies: $($_.directReplies), Position: $($_.position)" }

$env:PINCHTAB_URL = "http://localhost:9868"
$tabId = "tab_c3763dd8"

# Try to get the upvote counts for comments (HN doesn't show vote counts to non-logged-in users, 
# but we can check the comment IDs and use HN API)
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    var rows = document.querySelectorAll('.comtr');
    var topLevelIds = [];

    for (var i = 0; i < rows.length; i++) {
        var row = rows[i];
        var indEl = row.querySelector('.ind img');
        if (!indEl) continue;
        var indWidth = parseInt(indEl.getAttribute('width') || '0');
        if (indWidth === 0) {
            var id = row.getAttribute('id');
            var authorEl = row.querySelector('.hnuser');
            var author = authorEl ? authorEl.textContent.trim() : 'unknown';
            topLevelIds.push({id: id, author: author});
        }
    }

    return JSON.stringify(topLevelIds);
})()
"@
} | ConvertTo-Json)

$data = $response.result | ConvertFrom-Json
Write-Host "Top-level comment IDs:"
$data | ForEach-Object { Write-Host "ID: $($_.id), Author: $($_.author)" }

$ids = @("47368651", "47368975", "47372047")  # dimitri-vs, convenwis, wewewedxfgdf

foreach ($id in $ids) {
    $response = Invoke-RestMethod -Uri "https://hacker-news.firebaseio.com/v0/item/$id.json" -Method Get
    Write-Host "ID: $id, Author: $($response.by), Score: $($response.score), Kids: $(if ($response.kids) { $response.kids.Count } else { 0 })"
}

$env:PINCHTAB_URL = "http://localhost:9868"

# Re-navigate to refresh the page
$nav = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/navigate" -Method Post -ContentType "application/json" -Body (@{
    url = "https://news.ycombinator.com/item?id=47367129"
} | ConvertTo-Json)

Write-Host "New Tab ID: $($nav.tabId)"
$tabId = $nav.tabId

# Wait a bit for page to fully load
Start-Sleep -Seconds 3

# Get comment structure
$response = Invoke-RestMethod -Uri "$env:PINCHTAB_URL/evaluate" -Method Post -ContentType "application/json" -Body (@{
    tabId = $tabId
    expression = @"
(function() {
    var rows = document.querySelectorAll('.comtr');
    var allComments = [];

    for (var i = 0; i < rows.length; i++) {
        var row = rows[i];
        var indEl = row.querySelector('.ind img');
        if (!indEl) continue;
        var indWidth = parseInt(indEl.getAttribute('width') || '0');
        var depth = indWidth / 40;

        var authorEl = row.querySelector('.hnuser');
        var author = authorEl ? authorEl.textContent.trim() : 'unknown';
        var id = row.getAttribute('id');

        allComments.push({depth: depth, author: author, id: id});
    }

    // Score header info
    var scoreEl = document.querySelector('.score');
    var points = scoreEl ? scoreEl.textContent.trim() : 'N/A';

    // Comment count from header
    var subtextLinks = document.querySelectorAll('.subtext a');
    var commentCount = '';
    for (var i = 0; i < subtextLinks.length; i++) {
        var href = subtextLinks[i].getAttribute('href');
        if (href && href.startsWith('item')) {
            commentCount = subtextLinks[i].textContent.trim();
        }
    }

    // Build top-level with direct reply counts
    var tlComments = [];
    for (var i = 0; i < allComments.length; i++) {
        if (allComments[i].depth === 0) {
            var directReplies = 0;
            for (var j = i + 1; j < allComments.length; j++) {
                if (allComments[j].depth === 0) break;
                if (allComments[j].depth === 1) directReplies++;
            }
            tlComments.push({author: allComments[i].author, id: allComments[i].id, directReplies: directReplies});
        }
    }

    tlComments.sort(function(a, b) { return b.directReplies - a.directReplies; });

    return JSON.stringify({points: points, commentCount: commentCount, totalRows: allComments.length, topLevel: tlComments});
})()
"@
} | ConvertTo-Json)

$data = $response.result | ConvertFrom-Json
Write-Host "Points: $($data.points)"
Write-Host "Comment count: $($data.commentCount)"
Write-Host "Total comment rows: $($data.totalRows)"
Write-Host ""
Write-Host "Top-level comments sorted by direct replies:"
$data.topLevel | ForEach-Object { Write-Host "Author: $($_.author), ID: $($_.id), DirectReplies: $($_.directReplies)" }

# Export tabId for screenshot
Write-Host ""
Write-Host "TabID: $tabId"

